changeSet.sql:
CREATE OR REPLACE FUNCTION neutralize_retired_user_account_email()
RETURNS TRIGGER AS $$
BEGIN
    NEW.email := '';
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_neutralize_user_account_email ON user_account;
CREATE TRIGGER trg_neutralize_user_account_email
BEFORE INSERT OR UPDATE ON user_account
FOR EACH ROW EXECUTE FUNCTION neutralize_retired_user_account_email();

DROP TRIGGER IF EXISTS trg_neutralize_module_user_account_email ON module_user_account;
CREATE TRIGGER trg_neutralize_module_user_account_email
BEFORE INSERT OR UPDATE ON module_user_account
FOR EACH ROW EXECUTE FUNCTION neutralize_retired_user_account_email();

CREATE OR REPLACE FUNCTION neutralize_retired_study_contact_email()
RETURNS TRIGGER AS $$
BEGIN
    NEW.facility_contact_email := '';
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_neutralize_study_contact_email ON study;
CREATE TRIGGER trg_neutralize_study_contact_email
BEFORE INSERT OR UPDATE ON study
FOR EACH ROW EXECUTE FUNCTION neutralize_retired_study_contact_email();

DROP TRIGGER IF EXISTS trg_neutralize_module_study_contact_email ON module_study;
CREATE TRIGGER trg_neutralize_module_study_contact_email
BEFORE INSERT OR UPDATE ON module_study
FOR EACH ROW EXECUTE FUNCTION neutralize_retired_study_contact_email();

rollback.sql:
DROP TRIGGER IF EXISTS trg_neutralize_user_account_email ON user_account;
DROP TRIGGER IF EXISTS trg_neutralize_module_user_account_email ON module_user_account;
DROP FUNCTION IF EXISTS neutralize_retired_user_account_email();

DROP TRIGGER IF EXISTS trg_neutralize_study_contact_email ON study;
DROP TRIGGER IF EXISTS trg_neutralize_module_study_contact_email ON module_study;
DROP FUNCTION IF EXISTS neutralize_retired_study_contact_email();
